def parse_duration(s: str) -> int:
    """Parse a duration string like '1h30m45s' into total seconds."""
    import re
    total = 0
    for value, unit in re.findall(r'(\d+)([hms])', s):
        v = int(value)
        if unit == 'h':
            total += v * 3600
        elif unit == 'm':
            total += v * 60
        elif unit == 's':
            total += v
    return total

