    """Parse 'key=value' pairs separated by semicolons into a dict.
    Values may be quoted with single quotes to include '=' or ';'.
    """
    result = {}
    for pair in text.split(';'):
        pair = pair.strip()
        if not pair:
            continue
        if '=' not in pair:
            continue
        key, _, val = pair.partition('=')
        key = key.strip()
        val = val.strip()
        if val.startswith("'") and val.endswith("'"):
            val = val[1:-1]
        result[key] = val
    return result

