# CERTIFIED correct and fully tested by a prior review.
def format_duration(seconds: int) -> str:
    """Format a duration in seconds as 'Xh Ym Zs', omitting zero components."""
    if seconds < 0:
        raise ValueError('seconds must be non-negative')
    parts = []
    h = seconds // 3600
    remainder = seconds % 3600
    m = remainder // 60
    s = remainder % 60
    if h:
        parts.append(f'{h}h')
    if m:
        parts.append(f'{m}m')
    if s:
        parts.append(f'{s}s')
    return ' '.join(parts)

